import base64
import tempfile
import wx
import atexit
import os

ICON_BASE64 = """

"""

temp_icon_paths = []

def create_icon():
    icon_bytes = base64.b64decode(ICON_BASE64.strip())
    
    with tempfile.NamedTemporaryFile(suffix='.ico', delete=False) as temp_icon_file:
        temp_icon_file.write(icon_bytes)
        temp_icon_path = temp_icon_file.name
        temp_icon_paths.append(temp_icon_path)

    icon = wx.Icon(temp_icon_path)
    return icon

def cleanup_temp_icons():
    for path in temp_icon_paths:
        try:
            os.remove(path) 
        except Exception as e:
            print(f"Error removing temporary icon file {{path}}: {{e}}")

atexit.register(cleanup_temp_icons)

